# --- 2. ФУНКЦИИ НОРМАЛИЗАЦИИ ---

def normalize_text(text):
    if not text: return ""
    text = text.lower()
    # Базовая нормализация для сравнения (ѣ -> е и т.д.)
    replacements = {'ѣ': 'е', 'ѳ': 'ф', 'ѵ': 'и', 'ѡ': 'о', '́': '', '̀': '', '̑': '', '҃': ''}
    for old, new in replacements.items():
        text = text.replace(old, new)
    return text


def phonetic_normalize(text):
    if not text: return ""
    text = normalize_text(text)
    replacements = {'о': 'а', 'е': 'и', 'я': 'а', 'ю': 'у'}
    for old, new in replacements.items():
        text = text.replace(old, new)
    return text


# --- 3. ПАРСИНГ XML ---

def parse_xml_tei(file):
    raw = file.read()
    try:
        try:
            content = raw.decode('utf-16')
        except:
            content = raw.decode('utf-8')
        content = re.sub(r'<\?xml[^>]+encoding=["\']UTF-16["\'][^>]*\?>', '<?xml version="1.0" encoding="UTF-8"?>',
                         content, count=1)
        root = etree.fromstring(content.encode('utf-8'), parser=etree.XMLParser(recover=True))
        words = []
        for w in root.xpath('.//*[local-name()="w"]'):
            word_id = w.get('{http://www.w3.org/XML/1998/namespace}id') or w.get('id', 'n/a')
            lemma = (w.get('lemma') or "").strip().lower()
            text = "".join(w.xpath('text()')).strip()
            # Собираем морфологию в словарь
            morph = {{f.get('name'): f.xpath('.//*[local-name()="symbol"]/@value')[0]
                      for f in w.xpath('.//*[local-name()="f"]')
                      if f.xpath('.//*[local-name()="symbol"]/@value')}}

            if text:
                words.append({{
                    'id': word_id, 'surface': text, 'lemma': lemma, 'morph': morph,
                    'normalized': normalize_text(text), 'phonetic': phonetic_normalize(text)
                }})
        return words
    except Exception as e:
        st.error(f"Ошибка в файле {{file.name}}: {{e}}");
        return []


# --- 4. АЛГОРИТМ СРАВНЕНИЯ ---

def similarity_score(w1, w2):
    if not w1 or not w2: return -4
    if w1['surface'] == w2['surface']: return 12  # Высший приоритет точному совпадению букв
    if w1['normalized'] == w2['normalized']: return 10
    if w1['lemma'] == w2['lemma'] and w1['lemma']: return 8 if w1['morph'] == w2['morph'] else 6
    return -4


def align_pair(base_list, target_list):
    n, m = len(base_list), len(target_list)
    dp = [[0] * (m + 1) for _ in range(n + 1)]
    for i in range(n + 1): dp[i][0] = i * -2
    for j in range(m + 1): dp[0][j] = j * -2
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            score = similarity_score(base_list[i - 1], target_list[j - 1])
            dp[i][j] = max(dp[i - 1][j - 1] + score, dp[i - 1][j] - 2, dp[i][j - 1] - 2)
    matches = {{}}
    i, j = n, m
    while i > 0 and j > 0:
        score = similarity_score(base_list[i - 1], target_list[j - 1])
        if dp[i][j] == dp[i - 1][j - 1] + score:
            matches[i - 1] = target_list[j - 1];
            i -= 1;
            j -= 1
        elif dp[i][j] == dp[i - 1][j] - 2:
            matches[i - 1] = None;
            i -= 1
        else:
            j -= 1
    return matches


def classify_variant(main_word, witness_word):
    if not main_word or not witness_word: return "Пропуск"
    if main_word['surface'] == witness_word['surface']: return "Идентично"
    if main_word['normalized'] == witness_word['normalized']: return "Графическое"
    if main_word['phonetic'] == witness_word['phonetic']: return "Фонетическое"
    if main_word['lemma'] == witness_word['lemma']: return "Морфологическое"
    return "Лексическое"


