    others = [n for n in st.session_state.raw_data.keys() if n != main_file]
    if others:
        with st.spinner("Синхронизация текстов..."):
            all_aligns = {{name: align_pair(base_words, st.session_state.raw_data[name]) for name in others}}
            rows = []
            for i, bw in enumerate(base_words):
                row = {{"ID": bw['id'], "Лемма": bw['lemma'], "ЭТАЛОН": bw['surface']}}
                for name in others:
                    mw = all_aligns[name].get(i)
                    row[f"Слово ({{name}})"] = mw['surface'] if mw else "---"
                    row[f"Тип ({{name}})"] = classify_variant(bw, mw)
                rows.append(row)
            st.session_state.comp_df = pd.DataFrame(rows)
            st.session_state.others_list = others
            st.session_state.main_file = main_file

